cat > connect-volume/outbox/HMLCES18.B254.D0000001.d << 'EOF'



EOF

# 2. Arquivo de concessão (FHMLCON16)
echo "Gerando FHMLCON16.D0000001.d..."
cat > connect-volume/outbox/FHMLCON16.D0000001.d << 'EOF'

EOF

# 3. Arquivo genérico (FSUBCON10)
